parameters.jsCode:
// Dedup on issueId + updatedAt. Uses workflow static data so retries don't double-fire.
// Linear webhooks arrive wrapped: { headers, body: { action, data, ... } }. Unwrap .body;
// fall back to raw json for manual test calls or upstream nodes that already unwrapped.
const payload = $input.first().json.body || $input.first().json;
const action = payload.action;
const issue = payload.data || {};
const issueId = issue.id;
const updatedAt = issue.updatedAt;
const stateName = issue.state?.name;
const labels = (issue.labels || []).map(l => l.name);
const appLabel = labels.find(l => !l.startsWith('type:')) || 'global';
const typeLabel = labels.find(l => l.startsWith('type:')) || null;

// Only operate on issue events whose current state is one of our trigger statuses.
// Accept both 'update' (status moved INTO a trigger state) and 'create' (ticket
// filed already IN a trigger state — e.g., via Linear API with state pre-set).
// Dedup below keys on issueId:updatedAt so retries never double-fire.
const triggerStatuses = new Set(['Ready for Claude routines', 'Ready for agent build']);
if ((action !== 'update' && action !== 'create') || !triggerStatuses.has(stateName)) {
  return [{ json: { skip: true, reason: 'not-a-trigger-event', action, stateName } }];
}

// Dedup
const staticData = $getWorkflowStaticData('global');
staticData.seen = staticData.seen || {};
const key = `${issueId}:${updatedAt}`;
if (staticData.seen[key]) {
  return [{ json: { skip: true, reason: 'duplicate', key } }];
}
// Prune: keep only last 500 entries
const keys = Object.keys(staticData.seen);
if (keys.length > 500) {
  keys.slice(0, keys.length - 500).forEach(k => delete staticData.seen[k]);
}
staticData.seen[key] = Date.now();

return [{
  json: {
    skip: false,
    issueId,
    issueIdentifier: issue.identifier,
    issueTitle: issue.title,
    issueDescription: issue.description || '',
    issueUrl: issue.url,
    updatedAt,
    stateName,
    typeLabel,
    appLabel,
    allLabels: labels,
  }
}];

// Map type:* label to the routine fire endpoint + bearer token env var.
const input = $input.first().json;
const typeLabel = input.typeLabel;

const routines = {
  'type:architect':  { url: $env.ROUTINE_ARCHITECT_URL,  token: $env.ROUTINE_ARCHITECT_TOKEN,  name: 'Technical Architect' },
  'type:analyst':    { url: $env.ROUTINE_ANALYST_URL,    token: $env.ROUTINE_ANALYST_TOKEN,    name: 'Analyst' },
  'type:ux':         { url: $env.ROUTINE_UX_URL,         token: $env.ROUTINE_UX_TOKEN,         name: 'User Researcher' },
  'type:research':   { url: $env.ROUTINE_RESEARCH_URL,   token: $env.ROUTINE_RESEARCH_TOKEN,   name: 'AI Researcher' },
};

const routine = routines[typeLabel];
if (!routine || !routine.url) {
  throw new Error(`No routine configured for label ${typeLabel}`);
}

const firePayloadText = `Linear ticket ${input.issueIdentifier}: ${input.issueTitle}\n\n${input.issueDescription}\n\nLabels: ${input.allLabels.join(', ')}\nApp: ${input.appLabel}\nURL: ${input.issueUrl}`;

return [{
  json: {
    ...input,
    routineName: routine.name,
    routineUrl: routine.url,
    routineToken: routine.token,
    firePayload: { text: firePayloadText },
    firePayloadText,
  }
}];

// Classify Fire routine response. Returns { outcome } where outcome is 'ok' | 'capped' | 'failed'.
// Response shape from https://code.claude.com/docs/en/routines#trigger-a-routine is:
//   { type: 'routine_fire', claude_code_session_id: '...', claude_code_session_url: '...' }
const pickInput = $('Pick routine').item.json;
const resp = $input.first().json;
const status = resp.statusCode || resp.status || 0;
const body = resp.body || resp;

let outcome;
if (status >= 200 && status < 300) outcome = 'ok';
else if (status === 429) outcome = 'capped';
else outcome = 'failed';

return [{
  json: {
    ...pickInput,
    outcome,
    statusCode: status,
    responseBody: body,
    claude_code_session_id: body?.claude_code_session_id || null,
    claude_code_session_url: body?.claude_code_session_url || null,
  }
}];

parameters.jsonBody:
={{ JSON.stringify({
  query: `mutation CommentCreate($issueId: String!, $body: String!) { commentCreate(input: { issueId: $issueId, body: $body }) { success } }`,
  variables: {
