// 429 path: append to deferred_fires static data for the drainer workflow to pick up tomorrow.
const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.deferred_fires = staticData.deferred_fires || [];

const entry = {
  issueId: input.issueId,
  issueIdentifier: input.issueIdentifier,
  issueTitle: input.issueTitle,
  issueDescription: input.issueDescription,
  issueUrl: input.issueUrl,
  typeLabel: input.typeLabel,
  appLabel: input.appLabel,
  allLabels: input.allLabels,
  routineName: input.routineName,
  routineUrl: input.routineUrl,
  routineToken: input.routineToken,
  firePayloadText: input.firePayloadText,
  deferredAt: Date.now(),
};
staticData.deferred_fires.push(entry);

return [{ json: { ...input, deferredQueueSize: staticData.deferred_fires.length } }];

