parameters.jsCode:
// List Paperclip labels via n8n's this.helpers.httpRequest instead of the
// HTTP Request node. Reason: n8n 2.13.4's HTTP Request v4.2 auto-splits a
// JSON-array response into N items. When Paperclip returns `[]` (no labels
// yet), N=0 and every downstream node is skipped — `Resolve linear label`
// never runs, `Create linear label` never fires, and the first-seen ticket
// silently drops. A Code node always emits whatever it returns, independent
// of response shape.
const input = $input.first() ? $input.first().json : {};
const url = `${$env.PAPERCLIP_API_URL}/api/companies/${$env.PAPERCLIP_COMPANY_ID}/labels`;
let labels = [];
let statusCode = 0;
let error = null;
try {
  const body = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'Authorization': `Bearer ${$env.PAPERCLIP_API_KEY}` },
    json: true,
  });
  statusCode = 200;
  labels = Array.isArray(body) ? body : (body?.labels || body?.data || []);
} catch (err) {
  error = String(err && err.message ? err.message : err);
  statusCode = (err && err.statusCode) || 0;
}
return [{
  json: {
    ...input,
    labels,
    labelsStatusCode: statusCode,
    labelsError: error,
  }
}];

// Find-or-create the `linear:{identifier}` label in Paperclip.
// Upstream List Paperclip labels is a Code node that always emits one item.
const item = $input.first().json;
const labels = Array.isArray(item.labels) ? item.labels : [];
const target = `linear:${item.issueIdentifier}`;
const match = labels.find(l => l && l.name === target);
if (match && match.id) {
  return [{ json: { ...item, linearLabelId: match.id, needsLabelCreate: false } }];
}
return [{
  json: {
    ...item,
    linearLabelId: null,
    needsLabelCreate: true,
    labelCreatePayload: { name: target, color: '#5E6AD2' },
  }
}];

// POST /api/companies/:id/labels returns 201 with { id, name, color, ... }.
// Re-attach the ticket fields (which the HTTP node's output replaces with the response body)
// and hand off the new label UUID to `Build Paperclip payload`.
const ticket = $('Resolve linear label').item.json;
const resp = $input.first().json;
const newId = resp?.id || resp?.data?.id;
if (!newId) {
  throw new Error(`Create linear label returned no id. Response: ${JSON.stringify(resp).slice(0, 300)}`);
}
return [{
  json: {
    ...ticket,
    linearLabelId: newId,
    needsLabelCreate: false,
  }
}];

// Build Paperclip task payload.
// NOTE: Paperclip's createIssueSchema only accepts a narrow set of fields; anything extra
// is silently dropped. `linear_ticket_id`, `linear_issue_id`, `linear_url`, `app_id`, `labels`
// are kept here for forward-compat / debugging (they're harmless no-ops today). The Linear ->
// Paperclip link is actually persisted via `labelIds`, resolved by `Resolve linear label` /
// `Capture new label ID` upstream.
const input = $input.first().json;

const payload = {
  linear_ticket_id: input.issueIdentifier,
  linear_issue_id: input.issueId,
  linear_url: input.issueUrl,
  app_id: input.appLabel,
  title: input.issueTitle,
  description: input.issueDescription,
  labels: input.allLabels,
  labelIds: input.linearLabelId ? [input.linearLabelId] : [],
};

return [{ json: { ...input, paperclipPayload: payload } }];

